from pydantic import BaseModel
from typing import Optional
import json

class ImageResult(BaseModel):
    description: str
    text_content: Optional[str]
    confidence: str  # "high" | "low"

def extract_with_retry(client, image_data: str, task: str, max_retries: int = 2) -> ImageResult:
    prompt = f"{task}\nReturn JSON: {{description, text_content, confidence}}"
    for attempt in range(max_retries):
        resp = client.chat.completions.create(
            model="gpt-4o",
            response_format={"type": "json_object"},
            messages=[{"role": "user", "content": [
                {"type": "text", "text": prompt},
                {"type": "image_url", "image_url": {"url": f"data:image/png;base64,{image_data}"}}
            ]}]
        )
        try:
            return ImageResult(**json.loads(resp.choices[0].message.content))
        except Exception as e:
            prompt = f"Previous response caused: {e}. Return valid JSON: {{description, text_content, confidence}}"
    raise ValueError("Extraction failed after retries")
